import ProductValidation from '../classes/ProdactValidation.js';

class Product {
    #products = [];
    #ProductValidationClass = new ProductValidation();

    defaultImage = 'data:image/png;base64,';

    defaultImage2 = "data:image/png;base64,";

    defaultProducts = [
        {
            id: 1784642103791,
            title: "product 1",
            price: "100",
            image: this.defaultImage,
            background: 'bg-purple-500'
        },
        {
            id: 1784642214392,
            title: "product 2",
            price: "600",
            image: this.defaultImage2,
            background: 'bg-pink-500'
        },
        {
            id: 1784642124083,
            title: "product 3",
            price: "200",
            image: this.defaultImage2,
            background: 'bg-blue-500'
        },
        {
            id: 1784642146645,
            title: "product 4",
            price: "300",
            image: this.defaultImage,
            background: 'bg-green-500'
        },
        {
            id: 1784642167896,
            title: "product 5",
            price: "400",
            image: this.defaultImage2,
            background: 'bg-yellow-500'
        },
        {
            id: 1784642189887,
            title: "product 6",
            price: "500",
            image: this.defaultImage,
            background: 'bg-orange-500'
        },
        {
            id: 1784642231499,
            title: "product 7",
            price: "700",
            image: this.defaultImage,
            background: 'bg-red-500'
        },
        {
            id: 1784642214396,
            title: "product 8",
            price: "600",
            image: this.defaultImage2,
            background: 'bg-teal-500'
        },
    ];

    constructor(productList, modal) {
        this.productList = productList;
        this.modal = modal;
        this.setProductDeleteBtnEventListener();
    }

    async create(title, price, image, background) {
        let titleVal = title.value;
        let priceVal = price.value;
        let backgroundVal = background.value;

        let rawData = {
            title: titleVal,
            price: priceVal,
            image: image.files[0],
            background: backgroundVal,
        };

        if (!this.#ProductValidationClass.checkForm(rawData)) {
            return false;
        }

        let imageVal = await this.getBase64(image);

        const colors = {
            purple: "bg-purple-500",
            yellow: "bg-yellow-500",
            teal: "bg-teal-500",
            orange: "bg-orange-500",
            red: "bg-red-500",
            blue: "bg-blue-500",
            pink: "bg-pink-500",
            green: "bg-green-500"
        };

        let bgClass = colors[backgroundVal];

        let data = {
            id: Date.now(),
            title: titleVal,
            price: priceVal,
            image: imageVal,
            background: bgClass,
        };

        this.setProduct(data);

        let ProductCard = this.makeProductHTMLCard(data);
        this.setProductDeleteBtnEventListener();

        this.productList.innerHTML = ProductCard + this.productList.innerHTML;

        this.closeForm();
        return true;
    }

    makeProductHTMLCard(data) {
        return `<div class="productCard ${data.background}">
                <svg class="absolute bottom-0 left-0 mb-8 z-1" viewBox="0 0 375 283" fill="none"
                    style="transform: scale(1.5); opacity: 0.1;">
                    <rect x="159.52" y="175" width="152" height="152" rx="8" transform="rotate(-45 159.52 175)"
                        fill="white" />
                    <rect y="107.48" width="152" height="152" rx="8" transform="rotate(-45 0 107.48)" fill="white" />
                </svg>

                <div class="relative pt-10 px-10 flex items-center justify-center min-h-[208px]">
                    <div class="block absolute w-48 h-48 bottom-0 left-0 -mb-24 ml-3"
                        style="background: radial-gradient(black, transparent 60%); transform: rotate3d(0, 0, 1, 20deg) scale3d(1, 0.6, 1); opacity: 0.2;">
                    </div>

                    <img class="relative w-full"
                        src="${data.image}"
                        alt="">
                </div>

                <div class="relative text-white px-6 pb-6 mt-6">
                    <span class="block opacity-75 -mb-1">Outdoor</span>
                    <div class="flex justify-between">
                        <span class="block font-semibold text-xl truncate">${data.title}</span>
                        <span
                            class="truncate block bg-white rounded-full text-teal-500 text-xs font-bold px-3 py-2 leading-none flex items-center">$${data.price}</span>
                    </div>
                </div>

                <div class='text-center relative z-2'>
                    <button class="delete-btn text-red-300 font-bold bg-white w-full py-2 hover:cursor-pointer hover:text-red-500" data-id="${data.id}">delete</button>
                </div>
            </div>`;
    }

    openForm() {
        this.modal.classList.remove('hidden');
    }

    closeForm() {
        this.modal.classList.add('hidden');
    }

    getProducts() {
        this.#products = JSON.parse(localStorage.getItem("products")) || [];
        return this.#products;
    }

    setProduct(data) {
        this.getProducts();
        this.#products.unshift(data);
        localStorage.setItem("products", JSON.stringify(this.#products));
    }

    loadProducts() {
        this.getProducts();
        this.productList.innerHTML = "";

        if (localStorage.getItem("products") === null) {
            this.defaultProducts.forEach(product => {
                this.setProduct(product);
                this.productList.innerHTML = this.makeProductHTMLCard(product) + this.productList.innerHTML;
            });
        } else {
            this.#products.forEach(product => {
                this.productList.innerHTML += this.makeProductHTMLCard(product);
            });
        }

    }

    getBase64(fileInput) {
        return new Promise((resolve, reject) => {
            const file = fileInput.files[0];

            if (!file) {
                resolve("");
                return;
            }

            const reader = new FileReader();

            reader.onload = () => resolve(reader.result);
            reader.onerror = () => reject("Failed to read file.");

            reader.readAsDataURL(file);
        });
    }

    deleteProduct(id) {
        this.getProducts();
        this.#products = this.#products.filter(product => product.id !== id);

        localStorage.setItem("products", JSON.stringify(this.#products));

        this.loadProducts();
    }

    setProductDeleteBtnEventListener() {
        this.productList.addEventListener("click", (e) => {
            const deleteBtn = e.target.matches(".delete-btn") ? e.target : null;

            if (!deleteBtn) return;

            const id = Number(deleteBtn.dataset.id);

            Swal.fire({
                title: "Are you sure?",
                text: "This product will be deleted!",
                icon: "warning",
                showCancelButton: true,
                confirmButtonColor: "#d33",
                cancelButtonColor: "#3085d6",
                confirmButtonText: "Yes, delete it",
                cancelButtonText: "Cancel"
            }).then((result) => {
                if (result.isConfirmed) {
                    this.deleteProduct(id);

                    Swal.fire({
                        title: "Deleted!",
                        text: "The product has been deleted successfully.",
                        icon: "success",
                        timer: 1500,
                        showConfirmButton: false
                    });
                }
            });
        });
    }

}

export default Product;